import{_ as a,c as e,o as m,d as t}from"./plugin-vue_export-helper.23b45acd.js";const c='{"title":"\u0410\u0444\u043E\u0440\u0438\u0437\u043C 23","description":"","frontmatter":{"title":"\u0410\u0444\u043E\u0440\u0438\u0437\u043C 23","subtitle":"\u0428\u0438\u0432\u0430 \u0441\u0443\u0442\u0440\u0430 \u0432\u0438\u043C\u0430\u0440\u0448\u0438\u043D\u0438. \u0413\u043B\u0430\u0432\u0430 3.","tags":"vim-3","date":"2021-01-28T00:00:00.000Z"},"relativePath":"texts/shiva-sutra-vimarshini/3/23.md","lastUpdated":1626205911729}',r={},s=t('<div class="stanza"><a href="#s3.23" id="s3.23" class="num">3.23</a><div class="sans"><p>\u092F\u0926\u093E \u0924\u094D\u0935\u0928\u094D\u0924\u0930\u094D\u092E\u0941\u0916\u0924\u0941\u0930\u094D\u092F\u093E\u0935\u0927\u093E\u0928\u093E\u0935\u0937\u094D\u091F\u092E\u094D\u092D\u092A\u094D\u0930\u0915\u0930\u094D\u0937\u0932\u092D\u094D\u092F\u0902 \u0924\u0941\u0930\u094D\u092F\u093E\u0924\u0940\u0924\u092A\u0926\u092E\u0947\u0935\u092E\u092F\u0902 \u0928 \u0938\u092E\u093E\u0935\u093F\u0936\u0924\u094D\u092F\u092A\u093F \u0924\u0941 \u092A\u0942\u0930\u094D\u0935\u093E\u092A\u0930\u0915\u094B\u091F\u093F\u0938\u0902\u0935\u0947\u0926\u094D\u092F\u0924\u0941\u0930\u094D\u092F\u091A\u092E\u0924\u094D\u0915\u093E\u0930\u092E\u093E\u0924\u094D\u0930 \u090F\u0935 \u0938\u0928\u094D\u0924\u0941\u0937\u094D\u092F\u0928\u094D\u0928\u093E\u0938\u094D\u0924\u0947 \u0924\u0926\u093E\u0938\u094D\u092F\u2014</p><blockquote><p><strong>\u092E\u0927\u094D\u092F\u0947\u093D\u0935\u0930\u092A\u094D\u0930\u0938\u0935\u0903\u0965\u0968\u0969\u0965</strong></p></blockquote><p>\u092A\u0942\u0930\u094D\u0935\u093E\u092A\u0930\u0915\u094B\u091F\u094D\u092F\u094B\u0938\u094D\u0924\u0941\u0930\u094D\u092F\u0930\u0938\u092E\u093E\u0938\u094D\u0935\u093E\u0926\u092F\u0924\u094B \u092E\u0927\u094D\u092F\u0947 \u092E\u0927\u094D\u092F\u0926\u0936\u093E\u092F\u093E\u092E\u0935\u0930\u094B\u093D\u0936\u094D\u0930\u0947\u0937\u094D\u0920\u0903 \u092A\u094D\u0930\u0938\u0935\u094B \u0935\u094D\u092F\u0941\u0924\u094D\u0925\u093E\u0928\u093E\u0924\u094D\u092E\u093E \u0915\u0941\u0924\u094D\u0938\u093F\u0924\u0903 \u0938\u0930\u094D\u0917\u094B \u091C\u093E\u092F\u0924\u0947\u0964 \u0928 \u0924\u0941 \u0935\u093F\u0926\u094D\u092F\u093E\u0938\u0902\u0939\u093E\u0930\u0947 \u0924\u0926\u0941\u0924\u094D\u0925\u0938\u094D\u0935\u092A\u094D\u0928\u0926\u0930\u094D\u0936\u0928\u092E\u094D (\u0968-\u0967\u0966) \u0907\u0924\u094D\u092F\u0941\u0915\u094D\u0924\u0938\u0942\u0924\u094D\u0930\u093E\u0930\u094D\u0925\u0928\u0940\u0924\u094D\u092F\u093E \u0938\u0926\u093E \u0935\u094D\u092F\u093E\u092E\u0941\u0939\u094D\u092F\u0924\u0940\u0924\u094D\u092F\u0930\u094D\u0925\u0903\u0964 \u0909\u0915\u094D\u0924\u0902 \u0936\u094D\u0930\u0940\u092E\u093E\u0932\u093F\u0928\u0940\u0935\u093F\u091C\u092F\u0947</p><blockquote><p>\u0935\u093E\u0938\u0928\u093E\u092E\u093E\u0924\u094D\u0930\u0932\u093E\u092D\u0947\u093D\u092A\u093F \u092F\u094B\u093D\u092A\u094D\u0930\u092E\u0924\u094D\u0924\u094B \u0928 \u091C\u093E\u092F\u0924\u0947\u0964<br> \u0924\u092E\u0928\u093F\u0924\u094D\u092F\u0947\u0937\u0941 \u092D\u094B\u0917\u0947\u0937\u0941 \u092F\u094B\u091C\u092F\u0928\u094D\u0924\u093F \u0935\u093F\u0928\u093E\u092F\u0915\u093E\u0903\u0965<br> \u0924\u0938\u094D\u092E\u093E\u0928\u094D\u0928 \u0924\u0947\u0937\u0941 \u0938\u0902\u0938\u0915\u094D\u0924\u093F\u0902 \u0915\u0941\u0930\u094D\u0935\u0940\u0924\u094B\u0924\u094D\u0924\u092E\u0935\u093E\u091E\u094D\u091B\u092F\u093E\u0964</p></blockquote><p>\u0907\u0924\u093F \u092A\u094D\u0930\u093E\u0917\u092A\u093F \u0938\u0902\u0935\u093E\u0926\u093F\u0924\u092E\u094D\u0965\u0968\u0969\u0965</p></div><hr><div class="trans"><p>Yad\u0101 tvantarmukhatury\u0101vadh\u0101n\u0101va\u1E63\u1E6Dambhaprakar\u1E63alabhya\u1E41 tury\u0101t\u012Btapadamevamaya\u1E41 na sam\u0101vi\u015Batyapi tu p\u016Brv\u0101parako\u1E6Disa\u1E41vedyaturyacamatk\u0101ram\u0101tra eva santu\u1E63yann\u0101ste tad\u0101sya\u2014</p><blockquote><p><strong>Madhye&#39;varaprasava\u1E25||23||</strong></p></blockquote><p>P\u016Brv\u0101parako\u1E6Dyosturyarasam\u0101sv\u0101dayato madhye madhyada\u015B\u0101y\u0101mavaro&#39;\u015Bre\u1E63\u1E6Dha\u1E25 prasavo vyutth\u0101n\u0101tm\u0101 kutsita\u1E25 sargo j\u0101yate| Na tu vidy\u0101sa\u1E41h\u0101re tadutthasvapnadar\u015Banam (2-10) ityuktas\u016Btr\u0101rthan\u012Bty\u0101 sad\u0101 vy\u0101muhyat\u012Btyartha\u1E25| Ukta\u1E41 \u015Br\u012Bm\u0101lin\u012Bvijaye</p><blockquote><p>V\u0101san\u0101m\u0101tral\u0101bhe&#39;pi yo&#39;pramatto na j\u0101yate|<br> Tamanitye\u1E63u bhoge\u1E63u yojayanti vin\u0101yak\u0101\u1E25||<br> Tasm\u0101nna te\u1E63u sa\u1E41sakti\u1E41 kurv\u012Btottamav\u0101\xF1chay\u0101|</p></blockquote><p>iti pr\u0101gapi sa\u1E41v\u0101ditam||23||</p></div><hr><p>\u041E\u0434\u043D\u0430\u043A\u043E <em>(tu)</em>, \u043A\u043E\u0433\u0434\u0430 <em>(yad\u0101)</em> \u044D\u0442\u043E\u0442 [Yog\u012B] <em>(ayam)</em> \u043D\u0435 <em>(na)</em> \u0432\u0445\u043E\u0434\u0438\u0442 <em>(sam\u0101vi\u015Bati)</em> \u0442\u0430\u043A\u0438\u043C \u043E\u0431\u0440\u0430\u0437\u043E\u043C <em>(evam)</em> \u0432 \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0435 <em>(padam)</em> \u0437\u0430 \u043F\u0440\u0435\u0434\u0435\u043B\u0430\u043C\u0438 <em>(at\u012Bta)</em> Turya, \u0438\u043B\u0438 \u0427\u0435\u0442\u0432\u0435\u0440\u0442\u043E\u0433\u043E \u0421\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u044F <em>(turya)</em> --\u0442.\u0435. \u0432 Tury\u0101t\u012Bta, \u043D\u0430\u0437\u044B\u0432\u0430\u0435\u043C\u0443\u044E \u0442\u0430\u043A\u0436\u0435 Tur\u012By\u0101t\u012Bta, \u0412\u044B\u0441\u0448\u0435\u0435 \u0421\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0435--, \u043A\u043E\u0442\u043E\u0440\u043E\u0435 \u0434\u043E\u0441\u0442\u0438\u0436\u0438\u043C\u043E <em>(labhyam)</em> \u0447\u0435\u0440\u0435\u0437 \u0438\u043D\u0442\u0435\u043D\u0441\u0438\u0432\u043D\u043E\u0441\u0442\u044C <em>(yog\u012B)</em> \u0443\u0441\u0442\u043E\u0439\u0447\u0438\u0432\u043E\u0433\u043E \u0443\u0434\u0435\u0440\u0436\u0438\u0432\u0430\u043D\u0438\u044F <em>(ava\u1E63\u1E6Dambha)</em> [\u0435\u0433\u043E] \u0432\u043D\u0438\u043C\u0430\u043D\u0438\u044F <em>(avadh\u0101na)</em> \u043D\u0430 \u0432\u043D\u0443\u0442\u0440\u0435\u043D\u043D\u0435\u0439 <em>(antarmukha)</em> Turya <em>(turya)</em>, \u0430 \u043F\u043E-\u043F\u0440\u0435\u0436\u043D\u0435\u043C\u0443 <em>(api tu)</em> \u043F\u0440\u043E\u0434\u043E\u043B\u0436\u0430\u0435\u0442 <em>(\u0101ste)</em> \u043E\u0449\u0443\u0449\u0430\u0442\u044C \u043F\u043E\u043B\u043D\u0443\u044E \u0443\u0434\u043E\u0432\u043B\u0435\u0442\u0432\u043E\u0440\u0435\u043D\u043D\u043E\u0441\u0442\u044C <em>(santu\u1E63yan)</em> \u0442\u043E\u043B\u044C\u043A\u043E <em>(m\u0101tra\u1E25 eva)</em> \u0447\u0430\u043C\u0430\u0442\u043A\u0430\u0440\u043E\u0439 (camatk\u0101ra) --\u043D\u0430\u0441\u043B\u0430\u0436\u0434\u0435\u043D\u0438\u0435\u043C, \u043F\u043E\u043B\u043D\u044B\u043C \u0438\u0437\u0443\u043C\u043B\u0435\u043D\u0438\u044F-- <em>(camatk\u0101ra)</em> \u043E\u0442 Turya <em>(turya)</em>, \u0432\u043E\u0441\u043F\u0440\u0438\u043D\u0438\u043C\u0430\u0435\u043C\u043E\u0439 <em>(sa\u1E41vedya)</em> \u0432 \u043D\u0430\u0447\u0430\u043B\u044C\u043D\u044B\u0445 <em>(p\u016Brva)</em> [\u0438] \u043A\u043E\u043D\u0435\u0447\u043D\u044B\u0445 <em>(apara)</em> \u043C\u043E\u043C\u0435\u043D\u0442\u0430\u0445 <em>(ko\u1E6Di)</em> [\u0431\u043E\u0434\u0440\u0441\u0442\u0432\u043E\u0432\u0430\u043D\u0438\u044F, \u0441\u043D\u0430 \u0441\u043E \u0441\u043D\u043E\u0432\u0438\u0434\u0435\u043D\u0438\u044F\u043C\u0438 \u0438 \u0433\u043B\u0443\u0431\u043E\u043A\u043E\u0433\u043E \u0441\u043D\u0430], \u0442\u043E\u0433\u0434\u0430 <em>(tad\u0101)</em>, \u0432 \u0435\u0433\u043E \u0441\u043B\u0443\u0447\u0430\u0435 <em>(asya)</em>\u2014</p><blockquote><p><strong>\u041D\u0430 \u043F\u0440\u043E\u043C\u0435\u0436\u0443\u0442\u043E\u0447\u043D\u043E\u043C \u044D\u0442\u0430\u043F\u0435, [\u0442\u043E \u0435\u0441\u0442\u044C \u043D\u0438 \u043D\u0430 \u043D\u0430\u0447\u0430\u043B\u044C\u043D\u043E\u0439 \u0438 \u043D\u0438 \u043D\u0430 \u043A\u043E\u043D\u0435\u0447\u043D\u043E\u0439 \u0441\u0442\u0430\u0434\u0438\u044F\u0445 \u0431\u043E\u0434\u0440\u0441\u0442\u0432\u043E\u0432\u0430\u043D\u0438\u044F, \u0441\u043D\u0430 \u0441\u043E \u0441\u043D\u043E\u0432\u0438\u0434\u0435\u043D\u0438\u044F\u043C\u0438 \u0438 \u0433\u043B\u0443\u0431\u043E\u043A\u043E\u0433\u043E \u0441\u043D\u0430] <em>(madhye)</em>, \u043F\u0440\u043E\u0438\u0441\u0445\u043E\u0434\u0438\u0442 \u0432\u043E\u0437\u043D\u0438\u043A\u043D\u043E\u0432\u0435\u043D\u0438\u0435 <em>(prasava\u1E25)</em> \u043D\u0438\u0437\u0448\u0438\u0445 [\u043C\u0435\u043D\u0442\u0430\u043B\u044C\u043D\u044B\u0445 \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0439] <em>(avara)</em>||23||</strong></p></blockquote><p>\u0412 \u0441\u043B\u0443\u0447\u0430\u0435 Yog\u012B, \u043A\u043E\u0442\u043E\u0440\u044B\u0439 \u043D\u0430\u0441\u043B\u0430\u0436\u0434\u0430\u043B\u0441\u044F <em>(\u0101sv\u0101dayata\u1E25)</em> \u044D\u043B\u0438\u043A\u0441\u0438\u0440\u043E\u043C <em>(rasam)</em> Turya <em>(turya)</em> \u043D\u0430 \u043D\u0430\u0447\u0430\u043B\u044C\u043D\u043E\u0439 <em>(p\u016Brva)</em> [\u0438] \u043A\u043E\u043D\u0435\u0447\u043D\u043E\u0439 <em>(apara)</em> \u0441\u0442\u0430\u0434\u0438\u044F\u0445 <em>(ko\u1E6Dyo\u1E25)</em> [\u0442\u0440\u0435\u0445 \u043E\u0431\u044B\u0447\u043D\u044B\u0445 \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0439 \u0441\u043E\u0437\u043D\u0430\u043D\u0438\u044F], \u0432 madhya <em>(madhye)</em> \u2014\u043D\u0430 \u043F\u0440\u043E\u043C\u0435\u0436\u0443\u0442\u043E\u0447\u043D\u043E\u043C \u044D\u0442\u0430\u043F\u0435, \u0438\u043B\u0438 \u0441\u0442\u0430\u0434\u0438\u0438 <em>(madhya-da\u015B\u0101y\u0101m)</em>\u2014 \u0434\u0435\u0439\u0441\u0442\u0432\u0438\u0442\u0435\u043B\u044C\u043D\u043E \u0432\u043E\u0437\u043D\u0438\u043A\u0430\u0435\u0442 <em>(j\u0101yate)</em> avaraprasava --\u0431\u0443\u043A\u0432\u0430\u043B\u044C\u043D\u043E, \u043D\u0438\u0437\u0448\u0435\u0435 \u043F\u043E\u0440\u043E\u0436\u0434\u0435\u043D\u0438\u0435-- <em>(avara\u1E25... prasava\u1E25)</em>, \u0430 \u0438\u043C\u0435\u043D\u043D\u043E, \u043F\u0440\u0435\u0437\u0440\u0435\u043D\u043D\u043E\u0435 <em>(kutsita\u1E25)</em> \u043F\u0440\u043E\u044F\u0432\u043B\u0435\u043D\u0438\u0435 <em>(sarga\u1E25)</em> \u043D\u0438\u0437\u0448\u0438\u0445 [\u043C\u0435\u043D\u0442\u0430\u043B\u044C\u043D\u044B\u0445 \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0439] <em>(a\u015Bre\u1E63\u1E6Dha\u1E25)</em>, \u043A\u043E\u0442\u043E\u0440\u043E\u0435 \u0445\u0430\u0440\u0430\u043A\u0442\u0435\u0440\u043D\u043E \u0434\u043B\u044F vyutth\u0101na --\u043B\u044E\u0431\u043E\u0433\u043E \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u044F, \u043A\u0440\u043E\u043C\u0435 Sam\u0101dhi, \u0442.\u0435. vyutth\u0101na \u2014 \u044D\u0442\u043E \u043E\u0431\u044B\u0447\u043D\u043E\u0435 \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0435, \u043A\u043E\u0442\u043E\u0440\u043E\u0435 \u0438\u0441\u043F\u044B\u0442\u044B\u0432\u0430\u0435\u0442 \u0431\u043E\u043B\u044C\u0448\u0438\u043D\u0441\u0442\u0432\u043E \u043B\u044E\u0434\u0435\u0439-- <em>(vyutth\u0101na-\u0101tm\u0101)</em>|</p><p>&quot;\u041F\u0440\u0438 \u0438\u0441\u0447\u0435\u0437\u043D\u043E\u0432\u0435\u043D\u0438\u0438 <em>(sa\u1E41h\u0101re)</em> [\u0427\u0438\u0441\u0442\u043E\u0433\u043E] \u0417\u043D\u0430\u043D\u0438\u044F <em>(vidy\u0101)</em>, \u043F\u0440\u043E\u0438\u0441\u0445\u043E\u0434\u0438\u0442 \u043F\u043E\u044F\u0432\u043B\u0435\u043D\u0438\u0435 <em>(dar\u015Banam)</em> \u043C\u0435\u043D\u0442\u0430\u043B\u044C\u043D\u044B\u0445 \u0438\u0437\u043C\u0435\u043D\u0435\u043D\u0438\u0439 [\u043A\u0430\u043A \u0432\u043E \u0441\u043D\u0435] <em>(svapna)</em>, \u0432\u043E\u0437\u043D\u0438\u043A\u0430\u044E\u0449\u0438\u0445 <em>(uttha)</em> \u0438\u0437-\u0437\u0430 \u044D\u0442\u043E\u0433\u043E <em>(tad)</em>, [\u0442\u043E \u0435\u0441\u0442\u044C, &#39;\u0432\u043E\u0437\u043D\u0438\u043A\u0430\u044E\u0449\u0438\u0445 \u0438\u0437-\u0437\u0430 \u043F\u0440\u0435\u0434\u0448\u0435\u0441\u0442\u0432\u0443\u044E\u0449\u0435\u0433\u043E \u0438\u0441\u0447\u0435\u0437\u043D\u043E\u0432\u0435\u043D\u0438\u044F \u0427\u0438\u0441\u0442\u043E\u0433\u043E \u0417\u043D\u0430\u043D\u0438\u044F&#39;]. (II, 10) [\u0434\u0430\u043D\u043D\u043E\u0433\u043E \u041F\u0438\u0441\u0430\u043D\u0438\u044F] <em>(2-10 iti)</em>&quot;. \u041A\u0430\u043A \u0443\u043A\u0430\u0437\u0430\u043D\u043E \u0432 \u0437\u043D\u0430\u0447\u0435\u043D\u0438\u0438 <em>(artha-n\u012Bty\u0101)</em> \u0443\u043F\u043E\u043C\u044F\u043D\u0443\u0442\u043E\u0433\u043E <em>(ukta)</em> \u0430\u0444\u043E\u0440\u0438\u0437\u043C\u0430 <em>(s\u016Btra)</em>, \u043E\u043D \u043D\u0435 \u0432\u043F\u0430\u0434\u0430\u0435\u0442 \u0432 \u0437\u0430\u043C\u0435\u0448\u0430\u0442\u0435\u043B\u044C\u0441\u0442\u0432\u043E <em>(na tu... vy\u0101muhyati)</em> \u043F\u043E\u0441\u0442\u043E\u044F\u043D\u043D\u043E <em>(sad\u0101)</em>. \u042D\u0442\u043E \u0438\u043C\u0435\u0435\u0442\u0441\u044F \u0432 \u0432\u0438\u0434\u0443 <em>(iti artha\u1E25)</em>|</p><p>[\u0412 \u044D\u0442\u043E\u0439 \u0441\u0432\u044F\u0437\u0438, \u0431\u044B\u043B\u043E] \u0432\u044B\u0441\u043A\u0430\u0437\u0430\u043D\u043E <em>(uktam)</em> \u0432 \u0434\u043E\u0441\u0442\u043E\u0447\u0442\u0438\u043C\u043E\u043C M\u0101lin\u012Bvijayatantra <em>(\u015Br\u012B-m\u0101lin\u012Bvijaye)</em>:</p><blockquote><p>&quot;[\u041E\u0434\u043D\u0430\u043A\u043E,] \u0442\u043E\u0433\u043E, \u043A\u0442\u043E <em>(ya\u1E25... tam)</em> \u043D\u0435 <em>(na)</em> \u043F\u0440\u0435\u0431\u044B\u0432\u0430\u0435\u0442 <em>(j\u0101yate)</em> \u0432\u043D\u0438\u043C\u0430\u0442\u0435\u043B\u044C\u043D\u044B\u043C <em>(apramatta\u1E25)</em>, \u0434\u0430\u0436\u0435 \u043A\u043E\u0433\u0434\u0430 <em>(api)</em> \u043E\u043D \u0434\u043E\u0441\u0442\u0438\u0433\u0430\u0435\u0442 --\u0431\u0443\u043A\u0432\u0430\u043B\u044C\u043D\u043E, \u043F\u0440\u0438 \u0434\u043E\u0441\u0442\u0438\u0436\u0435\u043D\u0438\u0438-- <em>(l\u0101bhe)</em> \u0442\u043E\u043B\u044C\u043A\u043E <em>(m\u0101tra)</em> \u043B\u0430\u0442\u0435\u043D\u0442\u043D\u044B\u0445 \u043E\u0442\u043F\u0435\u0447\u0430\u0442\u043A\u043E\u0432, [\u043F\u043E\u0440\u043E\u0436\u0434\u0430\u044E\u0449\u0438\u0445 \u043E\u0433\u0440\u0430\u043D\u0438\u0447\u0435\u043D\u043D\u044B\u0435 \u0441\u0432\u0435\u0440\u0445\u044A\u0435\u0441\u0442\u0435\u0441\u0442\u0432\u0435\u043D\u043D\u044B\u0435 \u0441\u0438\u043B\u044B] <em>(v\u0101san\u0101)</em>, Vin\u0101yaka-s --\u043E\u043F\u0440\u0435\u0434\u0435\u043B\u0435\u043D\u043D\u044B\u0439 \u0442\u0438\u043F \u0434\u0435\u043C\u043E\u043D\u043E\u0432-- <em>(vin\u0101yak\u0101\u1E25)</em> \u043F\u043E\u0431\u0443\u0436\u0434\u0430\u044E\u0442 \u0438 \u043F\u0440\u0438\u043D\u0443\u0436\u0434\u0430\u044E\u0442 <em>(yojayanti)</em> \u043A \u043F\u0440\u0435\u0445\u043E\u0434\u044F\u0449\u0438\u043C <em>(anitye\u1E63u)</em> \u0443\u0434\u043E\u0432\u043E\u043B\u044C\u0441\u0442\u0432\u0438\u044F\u043C <em>(bhoge\u1E63u)</em>. \u0421\u043B\u0435\u0434\u043E\u0432\u0430\u0442\u0435\u043B\u044C\u043D\u043E <em>(tasm\u0101t)</em>, \u043F\u043E\u0441\u0440\u0435\u0434\u0441\u0442\u0432\u043E\u043C [\u0441\u0432\u043E\u0435\u0433\u043E] \u0436\u0435\u043B\u0430\u043D\u0438\u044F <em>(v\u0101\xF1chay\u0101)</em> [\u0434\u043E\u0441\u0442\u0438\u0436\u0435\u043D\u0438\u044F] \u0412\u044B\u0441\u0448\u0435\u0439 \u0420\u0435\u0430\u043B\u044C\u043D\u043E\u0441\u0442\u0438 <em>(uttama)</em>, [\u0442\u0430\u043A\u043E\u0439Yog\u012B] \u043D\u0435 \u0434\u043E\u043B\u0436\u0435\u043D \u0432\u0441\u0442\u0443\u043F\u0430\u0442\u044C \u0432 \u0442\u0435\u0441\u043D\u044B\u0439 \u043A\u043E\u043D\u0442\u0430\u043A\u0442 <em>(na... sa\u1E41saktim kurv\u012Bta)</em> \u0441 \u044D\u0442\u0438\u043C\u0438 [\u043F\u0440\u0435\u0445\u043E\u0434\u044F\u0449\u0438\u043C\u0438 \u0443\u0434\u043E\u0432\u043E\u043B\u044C\u0441\u0442\u0432\u0438\u044F\u043C\u0438] <em>(te\u1E63u... iti)</em>&quot;|</p></blockquote><p>[\u042D\u0442\u043E \u0431\u044B\u043B\u043E] \u043F\u0440\u043E\u0446\u0438\u0442\u0438\u0440\u043E\u0432\u0430\u043D\u043E <em>(sa\u1E41v\u0101ditam)</em> \u0440\u0430\u043D\u0435\u0435 <em>(pr\u0101k)</em> \u0442\u0430\u043A\u0436\u0435 <em>(api)</em> --\u0432 \u043A\u043E\u043C\u043C\u0435\u043D\u0442\u0430\u0440\u0438\u0438 \u043D\u0430 II, 10--<sup>1</sup>||23||</p><hr><ol><li>\u0421\u0442\u0440\u043E\u0444\u0430 \u0431\u044B\u043B\u0430 \u043F\u0440\u043E\u0446\u0438\u0442\u0438\u0440\u043E\u0432\u0430\u043D\u0430, \u043A\u043E\u0433\u0434\u0430 K\u1E63emar\u0101ja \u043A\u043E\u043C\u043C\u0435\u043D\u0442\u0438\u0440\u043E\u0432\u0430\u043B 10<sup>\u044B\u0439</sup> \u0430\u0444\u043E\u0440\u0438\u0437\u043C \u0432\u0442\u043E\u0440\u043E\u0439 \u0413\u043B\u0430\u0432\u044B. \u0421\u0442\u0440\u043E\u0444\u044B \u043F\u043E\u044F\u0432\u043B\u044F\u044E\u0442\u0441\u044F \u0442\u0430\u043C \u0444\u0440\u0430\u0433\u043C\u0435\u043D\u0442\u0430\u0440\u043D\u043E, \u0432\u043D\u0430\u0447\u0430\u043B\u0435 \u0434\u0432\u0435 \u0441\u0442\u0440\u043E\u043A\u0438, \u0430 \u0437\u0430\u0442\u0435\u043C \u043E\u0441\u0442\u0430\u0432\u0448\u0430\u044F\u0441\u044F \u0442\u0440\u0435\u0442\u044C\u044F \u043F\u0440\u043E\u0446\u0438\u0442\u0438\u0440\u043E\u0432\u0430\u043D\u044B \u043E\u0442\u0434\u0435\u043B\u044C\u043D\u043E, \u0431\u043B\u0438\u0436\u0435 \u043A \u043A\u043E\u043D\u0446\u0443 \u043A\u043E\u043C\u043C\u0435\u043D\u0442\u0430\u0440\u0438\u044F. \u042F \u0443\u043A\u0430\u0437\u0430\u043B \u0432\u0441\u0435 \u044D\u0442\u043E \u0432 \u043C\u043E\u0435\u043C \u043F\u0435\u0440\u0435\u0432\u043E\u0434\u0435 II, 10.</li></ol></div>',1),o=[s];function p(u,y,i,n,v,d){return m(),e("div",null,o)}var l=a(r,[["render",p]]);export{c as __pageData,l as default};
